#include <stdio.h>
int main() {
    int l, r, a, ans;
    scanf("%d%d%d", &l, &r, &a);
    int delta = (l > r) ? l - r : r - l;
    if (delta > a) {
        if (l > r) {
            ans = r + a;
        } else {
            ans = l + a;
        }
    } else {
        a -= delta;
        a /= 2;
        if (l > r) {
            ans = l + a;
        } else {
            ans = r + a;
        }
    }
    printf("%d\n", 2 * ans);

    return 0;
}

