macro_rules! scan {
    ( $string:expr, $sep:expr, $( $x:ty ),+ ) => {{
        let mut iter = $string.split($sep);
        ($(iter.next().and_then(|word| word.parse::<$x>().ok()).unwrap(),)*)
    }}
}

use std::io;

fn dist(l: &mut i32, r: &mut i32, a: &i32) {
    for _ in 0..*a {
        if l <= r {
            *l += 1;
        } else {
            *r += 1;
        }
    }
}

fn cnt(l: &i32, r: &i32) -> i32 {
    std::cmp::min(*l, *r) * 2
}

fn solve(mut l: i32, mut r: i32, a: i32) -> i32 {
    dist(&mut l, &mut r, &a);
    cnt(&l, &r)
}

fn main() {
    let mut buf = String::new();
    io::stdin().read_line(&mut buf).unwrap();

    let (l, r, a) = scan!(buf, char::is_whitespace, i32, i32, i32);

    println!("{}", solve(l, r, a));
}

#[cfg(test)]
mod test{
    use super::*;

    #[test]
    fn test_dist() { let (mut l, mut r, a) = (2, 3, 5);

        dist(&mut l, &mut r, &a);
        assert_eq!(l, 5);
        assert_eq!(r, 5);

        let (mut l, mut r, a) = (1, 5, 5);

        dist(&mut l, &mut r, &a);
        assert_eq!(l, 6);
        assert_eq!(r, 5);
    }

    #[test]
    fn test_cnt() {
        assert_eq!(cnt(&2, &3), 4);
        assert_eq!(cnt(&3, &4), 6);
        assert_eq!(cnt(&1, &0), 0);
        assert_eq!(cnt(&0, &0), 0);
    }

    #[test]
    fn acpt() {
        assert_eq!(solve(1, 4, 2), 6);
        assert_eq!(solve(5, 5, 5), 14);
        assert_eq!(solve(0, 2, 0), 0);
    }
}
